import { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);
  //     ↑ current value   ↑ updater
  //                                  ↑ initial value

  function handleClick() {
    setCount(count + 1); // tell React the new value
  }

  return <button onClick={handleClick}>Clicked {count} times</button>;
}

function App() {
  return (
    <>
      <Counter /> {/* has its own count */}
      <Counter /> {/* has its own count — independent */}
    </>
  );
}
// Clicking the first Counter does not affect the second one.

function Counter() {
  const [count, setCount] = useState(0);

  function handleClick() {
    setCount(count + 1);
    // count is still 0 here — the current render's snapshot
    console.log(count); // logs 0, not 1
    // On the NEXT render, count will be 1
  }

  return <button onClick={handleClick}>{count}</button>;
}

