import { useState } from 'react';

function Disclosure({ title, children }) {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div>
      <button
        onClick={() => setIsOpen(prev => !prev)}
        aria-expanded={isOpen}
      >
        {isOpen ? '▲' : '▼'} {title}
      </button>
      {isOpen && <div>{children}</div>}
    </div>
  );
}

import { useState } from 'react';

function SearchBox({ onSearch }) {
  const [query, setQuery] = useState('');

  return (
    <form onSubmit={e => { e.preventDefault(); onSearch(query); }}>
      <input
        type="text"
        value={query}
        onChange={e => setQuery(e.target.value)}
        placeholder="Search…"
      />
      <button type="submit">Go</button>
    </form>
  );
}

// Object state — always spread and override
const [user, setUser] = useState({ name: 'Alice', age: 30 });

function handleBirthday() {
  // WRONG: mutates the existing object — React won't see the change
  // user.age++;

  // CORRECT: create a new object with the updated field
  setUser({ ...user, age: user.age + 1 });
}

// Array state — always produce a new array
const [items, setItems] = useState(['apple', 'banana']);

function handleAddItem(newItem) {
  // CORRECT: create a new array
  setItems([...items, newItem]);
}

function handleRemoveItem(index) {
  // CORRECT: filter produces a new array
  setItems(items.filter((_, i) => i !== index));
}

// Every render evaluates this expression — wasteful for heavy computation
const [data, setData] = useState(expensiveComputation());

// Lazy initializer: the function is called only on the first render
const [data, setData] = useState(() => expensiveComputation());

// Typical use: reading from localStorage without re-reading on every render
const [theme, setTheme] = useState(() => {
  return localStorage.getItem('theme') ?? 'light';
});

// Parent owns the shared state
function TemperatureConverter() {
  const [celsius, setCelsius] = useState(0);
  const fahrenheit = celsius * 9 / 5 + 32;

  return (
    <div>
      <CelsiusInput value={celsius} onChange={setCelsius} />
      <FahrenheitDisplay value={fahrenheit} />
    </div>
  );
}

function CelsiusInput({ value, onChange }) {
  return (
    <label>
      Celsius:
      <input
        type="number"
        value={value}
        onChange={e => onChange(Number(e.target.value))}
      />
    </label>
  );
}

function FahrenheitDisplay({ value }) {
  return <p>{value.toFixed(1)} °F</p>;
}

import { useState, useRef } from 'react';

function Stopwatch() {
  const [elapsed, setElapsed] = useState(0);   // DISPLAYED — needs state
  const intervalRef = useRef(null);             // NOT displayed — just a ref

  function start() {
    const startTime = Date.now();
    intervalRef.current = setInterval(() => {
      setElapsed(Date.now() - startTime);
    }, 100);
  }

  function stop() {
    clearInterval(intervalRef.current); // read without triggering a re-render
  }

  return (
    <div>
      <p>{(elapsed / 1000).toFixed(1)}s</p>
      <button onClick={start}>Start</button>
      <button onClick={stop}>Stop</button>
    </div>
  );
}

