import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import Counter from './Counter';

test('increments count on button click', async () => {
  render(<Counter />);

  // Initial state
  expect(screen.getByRole('button')).toHaveTextContent('Clicked 0 times');

  // Simulate a click
  await userEvent.click(screen.getByRole('button'));

  // Assert the updated UI — not the internal state variable
  expect(screen.getByRole('button')).toHaveTextContent('Clicked 1 times');
});

test('each Counter instance has independent state', async () => {
  render(
    <>
      <Counter />
      <Counter />
    </>
  );

  const [firstButton, secondButton] = screen.getAllByRole('button');

  await userEvent.click(firstButton);
  await userEvent.click(firstButton);

  // First counter is at 2, second is still at 0
  expect(firstButton).toHaveTextContent('Clicked 2 times');
  expect(secondButton).toHaveTextContent('Clicked 0 times');
});
